import{_ as r,o as e,c as t,a7 as a}from"./chunks/framework.BgApuQ2e.js";const p="/images/absurdly-famous-people-probably-dont-know-enough/Venn2.png",n="/images/absurdly-famous-people-probably-dont-know-enough/Zones1-1024x763.png",l="/images/absurdly-famous-people-probably-dont-know-enough/AlexanderTheGreat_Bust-216x300.jpg",s="/images/absurdly-famous-people-probably-dont-know-enough/Alexander-map.png",u="/images/absurdly-famous-people-probably-dont-know-enough/Marco-Polo-300x225.jpg",i="/images/absurdly-famous-people-probably-dont-know-enough/Travels_of_Marco_Polo.svg_-1024x927.png",g="/images/absurdly-famous-people-probably-dont-know-enough/Che-234x300.jpg",b="/images/absurdly-famous-people-probably-dont-know-enough/MTE1ODA0OTcxODAxNTQ0MjA1-300x300.jpg",h="/images/absurdly-famous-people-probably-dont-know-enough/caesar-300x200.jpg",m="/images/absurdly-famous-people-probably-dont-know-enough/pinit_fg_en_rect_gray_20.png",P=JSON.parse(`{"title":"10 Absurdly Famous People You Probably Don't Know Enough About","description":"","frontmatter":{"title":"10 Absurdly Famous People You Probably Don't Know Enough About","titleZh":"10 位你可能了解不够的超级名人","date":"2014-05-14T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/05/absurdly-famous-people-probably-dont-know-enough.html","slug":"absurdly-famous-people-probably-dont-know-enough"},"headers":[],"relativePath":"posts/absurdly-famous-people-probably-dont-know-enough.md","filePath":"posts/absurdly-famous-people-probably-dont-know-enough.md","lastUpdated":1782886257000}`),d={name:"posts/absurdly-famous-people-probably-dont-know-enough.md"};function c(y,o,w,f,_,k){return e(),t("div",null,[...o[0]||(o[0]=[a('<h1 id="_10-位你可能了解不够的超级名人-·-10-absurdly-famous-people-you-probably-don-t-know-enough-about" tabindex="-1">10 位你可能了解不够的超级名人 · 10 Absurdly Famous People You Probably Don&#39;t Know Enough About <a class="header-anchor" href="#_10-位你可能了解不够的超级名人-·-10-absurdly-famous-people-you-probably-don-t-know-enough-about" aria-label="Permalink to &quot;10 位你可能了解不够的超级名人 · 10 Absurdly Famous People You Probably Don&#39;t Know Enough About&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/05/absurdly-famous-people-probably-dont-know-enough.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/05/absurdly-famous-people-probably-dont-know-enough.html</a> · 2014-05-14</p></blockquote><p>那段记忆已经是 14 年前的事了,但每次想起还是像昨天一样刺痛。</p><p>「我觉得他是一位很有名的老演员,」我说。当时我在和朋友玩一个游戏——你要引导队友说出你手上纸条上写的名字,而他们看不到纸条。</p><p>「亨弗莱·鲍嘉 (Humphrey Bogart)!」一个人喊道。</p><p>「卓别林 (Charlie Chaplin)。马龙·白兰度 (Marlon Brando)!」另一个人吼道。</p><p>我低头看着手里纸条上写的「亨利·基辛格 (Henry Kissinger)」几个字,心一下子沉了下去。我陷入了那种「我居然不知道这个超级有名的人是谁,而且马上就要被当众揭穿」的境地。没有任何感觉能比得上这个。</p><p>但你他妈的先别急着窃笑,因为关于著名历史人物这件事——他们的数量<em>多得离谱</em>。你会通过各种渠道了解这些人——学校、父母、书本、文章、电影,等等——但这个系统并不密不透风。你这辈子会不断地填补这些空白,但不管你是谁,总会在某处留下几个让人尴尬的空缺。我可以这样总结:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/Venn2.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="Danger Zone"></a></strong></p><p>每个人的「危险区」里都躺着一些名字。当心你的危险区。进一步拆解一下,面对一个著名人物的名字时,你可能落在下面这几个区域里:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/Zones1.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Zones"></a></p><p>第 1 区无疑是最危险的,而随着你年纪渐长,里面的大人物会越来越少(基辛格大惨案发生时我 18 岁——18 岁的人第 1 区里通常还堆着一堆大名字)。但大多数人到了成年,第 2 区仍然拥挤不堪,而那些<em>天天</em>被人挂在嘴边的名字,理想情况下是不应该出现在第 2 区的。</p><p>今天,我们要聚焦 10 个荒谬地有名、几乎堪称<em>神话级</em>的人物(比基辛格有名多了),但他们仍然待在很多人的第 2 区里(甚至可能有几个还在第 1 区)——等你读完这篇文章,他们应该都会被安置进你(和我)的第 3 区,你就安全了。为了列出这份名单,我调查了朋友和读者,问他们哪些巨型名字是自己羞于承认知之甚少的,而下面这些就是被反复提到的名字。</p><p>读的时候,你会发现有些人物本来就在你的第 3 区或第 4 区里,你甚至会奇怪他们怎么会出现在这份名单上。但要记住,每个人不同的人生经历都会留下他们独有的一套知识空白——空白出现在哪里通常纯属随机——你几乎一无所知的某些名字,在别人看来可能再基础不过。我们开始吧——</p><p><strong>亚历山大大帝 (Alexander the Great)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/AlexanderTheGreat_Bust.jpg" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Alexander the Great"></a></p><p><strong>生卒年:</strong> 公元前 356 – 前 323 年</p><p><strong>用 11 个字概括:</strong> 极大扩张了希腊文明版图的硬汉型征服者</p><p>**他的主要事迹:**亚历山大 20 岁那年,他的父亲——古马其顿王国的国王腓力二世 (Philip II)——被自己的一名侍卫刺杀身亡。腓力二世本来就有把王国扩张到波斯的军事野心,亚历山大继承的是一支已经准备好上战场的军队。但没人知道这小子到底是什么路数——结果证明,权力刚刚被交到了历史上最高产的征服者之一手里。在接下来的 12 年里,亚历山大不仅完成了他父亲的野心,还走得远远超出——一路打进埃及,东边一直打到今天的巴基斯坦。夸张的是他这才刚刚开始——他公开宣称的扩张目标是「世界的尽头和大外海」,而且他正走在这条路上(他曾向印度推进,下一步计划是拿下阿拉伯半岛)——却在 32 岁时死于某种疾病(也可能是被暗杀)。</p><p>亚历山大大帝特别酷的一点是,*这一切他都是在 20 多岁完成的。*他就是个 20 几岁的小伙子,在短短 12 年里干了这些事:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/Alexander-map.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Alexander map"></a></strong></p><h3 id="修改自原图。" tabindex="-1">修改自<a href="http://www.worldhistorymaps.info/images/Alexander_323bc.jpg" target="_blank" rel="noreferrer">原图</a>。 <a class="header-anchor" href="#修改自原图。" aria-label="Permalink to &quot;修改自[原图](http://www.worldhistorymaps.info/images/Alexander_323bc.jpg)。&quot;">​</a></h3><p>这是古希腊历史上最大的帝国,尽管在他死后不久便开始衰落,他的征服却让希腊文化传播到了极远之地,并开启了古希腊文明的希腊化时期 (Hellenistic Period),其影响一直延续到近 2000 年后的拜占庭帝国。</p><p><strong>其他事情:</strong></p><ul><li>他 13 到 16 岁之间的主要老师不是别人,正是亚里士多德 (Aristotle)。这俩人经常单独待在一个房间里,<em>非常</em>诡异。我特别想知道他们聊了些什么,有什么只有他俩懂的私人笑话,亚里士多德又给亚历山大提过什么人生建议。想象亚里士多德来上课,发现亚历山大大帝没写作业还挺气恼的画面,也挺有意思。</li><li>这段关系后来变得很糟糕,亚历山大晚年变得多疑,给亚里士多德寄过威胁信。有些理论甚至认为,亚里士多德可能与亚历山大之死有关。</li><li>他的统治以《权力的游戏》的方式开场。他父亲——那位国王——去世时有个新妻子,亚历山大掌权时,他母亲(也就是国王的前妻)把这位新妻子和她的女儿活活烧死了。亚历山大还处决了其他几个潜在的政治对手,之后当一系列邻近的希腊城邦反抗他的统治时,亚历山大把它们的城市夷为平地,一个一个击败,直到把整个希腊都收入囊中。然后他就开始向外扩张了。</li><li>他母亲可真是个人物。除了活烧情敌女人的爱好之外,她还是终极的野心勃勃的虎妈,不停地烦亚历山大让他去征服世界,并让他(和其他人)相信她在结婚之前被宙斯搞怀孕了,亚历山大是宙斯的儿子。</li><li>亚历山大一生征战从未败绩,尽管经常寡不敌众。</li><li>尽管他在征服和政治上心狠手辣,但对战死者的家人却出奇地宽厚,免除他们的赋税和公共服务。</li><li>亚历山大建立了 20 多座以自己名字命名的城市,包括埃及的亚历山大港 (Alexandria)。</li><li>一些历史学家认为亚历山大是双性恋,并且和他最好的朋友赫费斯提翁 (Hephaestion) 有过恋情。他也有一个后宫,但很少&quot;使用&quot;。</li><li>据说他一只眼睛是棕色的,另一只是蓝色的。</li><li>希特勒试图做的事情,本质上和亚历山大试图做的是一样的(不过带有更多的种族灭绝色彩),但因为年代太久远,那种悲剧性的东西今天已经没什么情感冲击了。如果希特勒是在 2400 年前干他那些事儿,今天我们说不定会叫他&quot;希特勒大帝&quot;。</li></ul><p><strong>2014 年的对应人物:</strong> 马克·扎克伯格</p><p><strong>马可·波罗 (Marco Polo)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/Marco-Polo.jpg" target="_blank" rel="noreferrer"><img src="'+u+'" alt="Marco Polo"></a></p><p><strong>在世时间:</strong> 1254 – 1324</p><p><strong>11 个字概括:</strong> 24 年航行后首位记录亚洲之行的欧洲人</p><p><strong>他的主要事迹:</strong> 马可·波罗 15 岁那年才第一次见到自己的父亲和叔叔,他俩都是走商,当时正结束一次漫长的航行回到威尼斯。他们没浪费时间,立刻开始筹划下一次航行,这次带上了 17 岁的马可。这趟航行史诗般地持续了整整 <em>24 年</em>,过程是这样的:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/Travels_of_Marco_Polo.svg_.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Marco Polo Journey"></a></strong></p><p>让马可·波罗 (Marco Polo) 如此有名的原因,并不是他是第一个探索亚洲的欧洲人——他不是——而是他是第一个把这事儿<em>记录下来</em>的人,写在他的书《马可·波罗游记》(The Travels of Marco Polo) 里。他在 40 岁出头时结束了 24 年的旅程回到威尼斯,并作为一名富商在那里度过了余生。</p><p><strong>其他事情:</strong></p><ul><li>他旅行归来时发现威尼斯正和敌对城邦热那亚 (Genoa) 打仗。他加入战斗,很快就被关进了监狱。他那本著名的书就是在监狱里写的——只不过,他没有亲自写。他口述给了他的狱友,而那位狱友正好是个言情小说作家。</li><li>在中国,波罗一家和蒙古首领(成吉思汗的孙子)忽必烈 (Kublai Khan) 成了朋友,马可为他当了几年使节。忽必烈舍不得他们,不肯让波罗一家离开,但当一位蒙古公主需要护送到波斯嫁给国王时,波罗一家接下了这个活儿。那趟漫长的海上航行(见地图)非常不愉快——数百名乘客中只有 18 人幸存,但波罗一家三口都活了下来。</li><li>波罗第一次看到大象、鳄鱼、猴子和犀牛时惊得目瞪口呆,把它们误当成了神话生物(他以为犀牛是独角兽)。这完全合理——想象一下,如果你从没见过这些动物,它们看起来会有多怪。</li><li>关于波罗把意大利面或披萨带到意大利的说法完全是瞎编,但他确实带回了关于纸币的故事,那在当时的欧洲还是个未知的概念。</li><li>哥伦布 (Christopher Columbus) 对波罗的旅行患上了 FOMO(错失恐惧症),这是他成为探险家的主要原因之一。他随身总带着一本波罗的书。</li></ul><p><strong>2014 年的等价物:</strong> 好奇号火星车 (Curiosity Rover)</p><p><strong>切·格瓦拉 (Che Guevara)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/Che.jpg" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Che Guevara"></a></p><p><strong>在世时间:</strong> 1928 – 1967</p><p><strong>11 个字概括:</strong> 有魅力、有争议、冷酷无情的马克思主义革命者,反叛与反主流文化的永恒符号</p><p><strong>他主要干了啥:</strong> 我不可能是唯一一个花了一辈子都搞不懂为啥 T 恤上那个哥们儿这么有名的人吧。马里兰艺术学院 (Maryland Institute College of Art) 把上面那张照片(在一次追悼会上拍的)称为「世界上最著名的照片」,而今天,这张图已经成了一个无处不在的标志,象征着对权威、资本主义和帝国主义的反抗。可他到底是谁呢?</p><p>切 (Che) 在阿根廷长大,是个热爱数学、下国际象棋的知识分子,拿到医学学位当上医生后,决定还是当个酷炫大哥更带劲。他带着这份野心跑去墨西哥,在那儿认识了卡斯特罗兄弟,俩边一拍即合——因为双方都恨美国,都把世界上大部分苦难归咎于资本主义帝国主义。他跟着卡斯特罗兄弟回到古巴,帮忙推翻了政府,成了菲德尔·卡斯特罗 (Fidel Castro) 新政权的核心人物,一边当着残酷处决政敌的刽子手,一边当着财政部长,把古巴的贸易关系从美国那边掰向苏联。他是个精力旺盛的家伙,花了大量时间在别的国家煽动革命,直到搞砸了被 CIA 协助的玻利维亚军方抓住,在 39 岁被处决。</p><p><strong>其他事情:</strong></p><ul><li>他在今天是个极具争议的人物,一部分人把他当作反主流文化的励志符号来热爱,另一部分人把他当作反主流文化的令人厌烦的符号来痛恨。</li><li>大家不太清楚的是,他除了是个英勇的革命者,还是个冷酷的杀人犯,在古巴不经审判处决了几百号人。</li><li>他死前设法把自己胆怯的行刑者给震住了,冲他吼道:「开枪啊,你个懦夫!你不过是要杀一个人罢了!」</li><li>他以臭闻名,一周才换一次衬衫,还挺自豪的。</li><li>他的蜜月看起来<a href="http://s3.amazonaws.com/somewherein/pictures/RIAD95/06-2013/RIAD95_93641479351ba4240917ae5.49372628_xlarge.jpg" target="_blank" rel="noreferrer">挺糟心的</a>。<a href="#footnote-1-1499">1</a></li></ul><p><strong>2014 年对应版本:</strong> 占领华尔街 (Occupy Wall Street) 和基地组织 (al-Qaeda) 的某种混合体</p><p><strong>特蕾莎修女 (Mother Teresa)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/MTE1ODA0OTcxODAxNTQ0MjA1.jpg" target="_blank" rel="noreferrer"><img src="'+b+'" alt="Mother Teresa"></a></p><p><strong>生卒:</strong> 1910 – 1997</p><p><strong>11 个字概括:</strong> 一个善良的、可能有点讨人厌的修女,把自己奉献给了穷人</p><p><strong>她的主要事迹:</strong> 特蕾莎修女决定用一种烦人的方式度过一生——把她拥有的一切都奉献给「服务最穷的穷人」,让我们其他人相形见绌。她是阿尔巴尼亚族人,在奥斯曼帝国长大(在今天的马其顿境内),18 岁那年搬去印度当修女。接下来的 17 年,她就是这么过的——一个修女兼教师,而她似乎也挺满足于此,直到耶稣(她说的)告诉她别再当废柴了,去帮帮身边那些穷得离谱的人吧。于是她转变了道路,创立了「仁爱传教修女会 (Missionaries of Charity)」,这个组织除了别的事情之外,还为贫穷的病人开办临终关怀院,好让那些「活得像动物一样的人可以死得像天使一样」。她证明了自己相当有创业头脑,借助日益增长的名气把工作扩展到海外,最终把她的慈善事业规模化到了 133 个国家,并有 4500 名修女参与其中。她 1979 年获得了诺贝尔和平奖,如今算是一切美好事物的象征。</p><p><strong>其他事情:</strong></p><ul><li>尽管她生活简朴,但其实她出生在一个富裕的家庭。</li><li>她极为贞洁。真是浪费了一个要点。</li><li>尽管她整体名声光辉,但围绕她的遗产也有一些争议,主要集中在她高调反对避孕(甚至有人认为她夸大了印度的糟糕程度以博取更多关注),以及她拒绝采用西方医疗标准、宁愿使用条件较差的设施,因为她相信「苦难」能让人更接近基督。</li></ul><p><strong>2014 年的对应人物:</strong> 某个你从没听过的 NGO,因为像特蕾莎修女这样的人通常并不出名</p><p><strong>尤利乌斯·凯撒 (Julius Caesar)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/05/caesar.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Julius Caesar"></a></p><p><strong>生卒:</strong> 公元前 100 – 前 44 年</p><p><strong>11 个字概括:</strong> 为罗马帝国奠基的罗马将军兼独裁者</p><p><strong>主要成就:</strong> 他出身平凡,而且起步其实相当晚。32 岁那年他访问西班牙,看到一尊亚历山大大帝的雕像,心情立刻变得很糟,因为他觉得自己一事无成(典型的 <a href="https://waitbutwhy.com/2013/09/why-generation-y-yuppies-are-unhappy.html" target="_blank" rel="noreferrer">GYPSY</a>)。他当时才刚开始做祭司,结果家乡一场敌对派系的战争结局对他不利,把他从这个职位上赶了下来——于是他转向了军队。他在军衔和政治影响力上稳步上升,最终压制了软弱的元老院,推翻了罗马共和国,并被宣布为独裁者。</p><p>他是一位优秀的领导者,深受大多数人爱戴,对宪法、法律和政府结构进行了全面改革,为罗马帝国奠定了基础,而罗马帝国在他被暗杀后又繁荣了近 500 年。</p><p><strong>其他事情:</strong></p><ul><li>凯撒是个狠角色。他年轻时曾经被海盗抓住扣押,海盗要求用二十塔兰特白银赎他,他打断海盗,坚持让他们要五十塔兰特——海盗后来也确实拿到了这笔钱。他被释放后,集结了自己的舰队,追上海盗,夺回了钱,还把他们全都钉上了十字架——他被扣押时就告诉过海盗他会这么干,当时海盗还嘲笑他。</li><li>凯撒和克利奥帕特拉 (Cleopatra) 有过一段完整的恋情,地点既在埃及,也在凯撒罗马近郊的别墅里,她会去那儿探访他。这就像亚里士多德教亚历山大大帝一样,我完全没法接受两个 <em>这么</em> 传奇的人物居然一起厮混、上床、抱在一起睡觉。就是很怪。<a href="#footnote-2-1499">2</a> 更多内容见下一页克利奥帕特拉部分。</li><li>他被自己推翻的一群旧贵族刺杀,但那群人无法自己上位,因为民众爱戴凯撒,他们没有支持。相反,凯撒指定的继承人屋大维 (Octavian)(凯撒的侄孙,因为他没有儿子)成为了第一位罗马皇帝(以奥古斯都之名登基)。</li><li>莎士比亚的戏剧和真实的故事很容易搞混,我聊过的一些人甚至问凯撒到底是真实存在还是虚构人物。答案是他绝对真实存在,而且莎士比亚的剧情跟史实相差也不远。马克·安东尼确实是他的二把手,凯撒确实被(约 60 个)不同的人捅了很多刀(23 刀),布鲁图斯 (Brutus) 也确实是凯撒信任的人,并且是刺杀他的人之一。不过,「Et tu, Brute?(吾儿,你也有份?)」这句话是虚构的。</li><li>凯撒带来的一项持续至今的改变是历法。当时人们用月亮定历,月份和年份都不规律。他改用了以太阳为基础的历法,把一年定为 365.25 天(加入闰年来处理那 0.25 天),并且在公元前 46 年多加了三个月来让日期跟季节对齐,公元前 45 年从 1 月 1 日开始。我们今天仍在沿用这些改变。</li></ul><p>**2014 年的对应人物:**史蒂夫·乔布斯</p><p><a href="https://waitbutwhy.com/2014/05/absurdly-famous-people-probably-dont-know-enough.html/2" target="_blank" rel="noreferrer">第 2 页(比利小子、伽利略、孔子、克利奥帕特拉、甘地)→</a></p><hr><ol><li><p>不知怎么的,我把前面所有内容打进去时进度一直没保存,等我不小心离开页面时,我关于亚历山大、马可·波罗和切·格瓦拉写的所有东西都没了。这一条标志着我终于回到了几个小时前的进度。至少要过一个月我才能再谈起这件事。<a href="#note-1-1499">↩</a></p></li><li><p>这种现象最接近的现代例子是肯尼迪 (JFK) 和玛丽莲·梦露 (Marilyn Monroe)。<a href="#note-2-1499">↩</a></p></li></ol><p>页数: 1 <a href="https://waitbutwhy.com/2014/05/absurdly-famous-people-probably-dont-know-enough.html/2" target="_blank" rel="noreferrer">2</a></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/05/absurdly-famous-people-probably-dont-know-enough.html&amp;description=10%20Absurdly%20Famous%20People%20You%20Probably%20Don%E2%80%99t%20Know%20Enough%20About" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p>',68)])])}const x=r(d,[["render",c]]);export{P as __pageData,x as default};
